member.example:
Bind the HorizontalOrVerticalLayoutGroup spacing property using a serialized binder field — the target HorizontalOrVerticalLayoutGroup is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private HorizontalOrVerticalLayoutSpacingBinder _spacing;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _spacing;
    }


Bind the HorizontalOrVerticalLayoutGroup spacing property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private HorizontalOrVerticalLayoutGroup _layoutGroup;
        
        private HorizontalOrVerticalLayoutSpacingBinder Spacing =>
            new(_layoutGroup);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _spacing;
    }

Switch the HorizontalOrVerticalLayoutGroup spacing between two values using a serialized binder field — the target HorizontalOrVerticalLayoutGroup is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private HorizontalOrVerticalLayoutSpacingSwitcherBinder _isCompact;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isCompact;
    }


Switch the HorizontalOrVerticalLayoutGroup spacing between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private HorizontalOrVerticalLayoutGroup _layoutGroup;
        
        [SerializeField] 
        private float _compactSpacing;
        
        [SerializeField] 
        private float _normalSpacing;
        
        private HorizontalOrVerticalLayoutSpacingSwitcherBinder IsCompact => new(
            _layoutGroup, _compactSpacing, _normalSpacing);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isCompact;
    }
